package entity

import (
	"math"
	"testing"
)

// TestUnitOrderCalculateTotalEdgeCases adds a set of edge‑case scenarios for
// Order.CalculateTotal().  The existing test suite already covers the happy
// paths (empty order, single item, large order).  Here we focus on situations
// that are easy to miss when the implementation is changed:
//
//   1. Items with a quantity of 0 – they must not affect the total.
//   2. Items with a unit price of 0 – they must not affect the total.
//   3. Negative quantities or prices – the method is a pure arithmetic
//      accumulator, so the sign should be preserved (validation is performed
//      elsewhere, the calculator itself must not panic or drop the sign).
//   4. Mixed positive/negative values – the net total must be the exact sum.
//   5. Very large numbers – the calculation must stay inside the int64 range
//      (the code uses int64 for cents, so we test the upper‑boundary without
//      causing an overflow).
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	t.Parallel()

	type testCase struct {
		name     string
		items    []OrderItem
		expected int64 // total is stored as int64 (cents)
	}

	cases := []testCase{
		{
			name: "zero_quantity",
			items: []OrderItem{
				{ProductID: 1, Quantity: 0, UnitPrice: 1999}, // 0 × 19.99 = 0
				{ProductID: 2, Quantity: 3, UnitPrice: 500}, // 3 × 5.00 = 1500
			},
			expected: 1500,
		},
		{
			name: "zero_price",
			items: []OrderItem{
				{ProductID: 1, Quantity: 2, UnitPrice: 0},   // 2 × 0 = 0
				{ProductID: 2, Quantity: 1, UnitPrice: 2500}, // 1 × 25.00 = 2500
			},
			expected: 2500,
		},
		{
			name: "negative_quantity",
			items: []OrderItem{
				{ProductID: 1, Quantity: -2, UnitPrice: 1500}, // -2 × 15.00 = -3000
				{ProductID: 2, Quantity: 5, UnitPrice: 800},   // 5 × 8.00 = 4000
			},
			expected: 1000,
		},
		{
			name: "negative_price",
			items: []OrderItem{
				{ProductID: 1, Quantity: 3, UnitPrice: -1200}, // 3 × -12.00 = -3600
				{ProductID: 2, Quantity: 2, UnitPrice: 2500},  // 2 × 25.00 = 5000
			},
			expected: 1400,
		},
		{
			name: "mixed_signs",
			items: []OrderItem{
				{ProductID: 1, Quantity: -1, UnitPrice: -1000}, // -1 × -10.00 = 1000
				{ProductID: 2, Quantity: 2, UnitPrice: -1500},  // 2 × -15.00 = -3000
				{ProductID: 3, Quantity: 3, UnitPrice: 2000},   // 3 × 20.00 = 6000
			},
			expected: 4000,
		},
		{
			name: "large_numbers_no_overflow",
			items: []OrderItem{
				{
					ProductID: 1,
					Quantity:  math.MaxInt64 / 2000, // keep product * price < MaxInt64
					UnitPrice: 2000,
				},
				{
					ProductID: 2,
					Quantity:  1,
					UnitPrice: 1,
				},
			},
			// Expected total = (MaxInt64/2000)*2000 + 1 = MaxInt64 + 1,
			// but we deliberately chose the divisor so the multiplication stays
			// inside the int64 range.  The exact value is MaxInt64 - (MaxInt64 % 2000) + 1.
			expected: (math.MaxInt64 / 2000 * 2000) + 1,
		},
	}

	for _, tc := range cases {
		tc := tc // capture range variable
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()

			ord := &Order{
				Items: tc.items,
			}
			got := ord.CalculateTotal()
			if got != tc.expected {
				t.Fatalf("unexpected total: want %d, got %d", tc.expected, got)
			}
		})
	}
}
```

### Why this test does **not** duplicate existing ones
| Existing test | What it covers | What this test adds |
|---------------|----------------|---------------------|
| `TestUnitOrderCalculateTotal` | General case with a few items (positive quantities & prices) | Edge‑cases with zero, negative, and very large values |
| `TestUnitOrderCalculateTotalEmpty` | Empty slice → total = 0 | Already covered, but we keep a zero‑quantity item to verify that a *non‑empty* slice containing a zero‑quantity line still yields the correct sum |
| `TestUnitOrderCalculateTotalSingleItem` | One normal item | No overlap – we test a single item with zero price |
| `TestUnitOrderCalculateTotalLargeOrder` | Many items (stress test) | We test the arithmetic limits (max int64) and sign handling, which are not exercised by the “large order” test |

The test follows the project's conventions:
* Table‑driven with `t.Run`.
* Uses `t.Parallel()` for speed and isolation.
* Lives in the same `entity` package as the production code.
* Does **not** touch the repository, use‑case, or handler layers, keeping it a pure unit test.

**Файл:** `internal/handler/api_test.go`  
**Тест:** `TestAPIOrderFullFlowCancel`

```go
package handler_test

import (
	"bytes"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strconv"
	"testing"

	"beanbrew/internal/handler"
	"beanbrew/internal/repository/sqlite"
	"beanbrew/internal/usecase"
)

// helper – делает запрос и проверяет код ответа
func doRequest(t *testing.T, client *http.Client, method, url string, body any, wantStatus int) *http.Response {
	var reqBody *bytes.Reader
	if body != nil {
		b, err := json.Marshal(body)
		if err != nil {
			t.Fatalf("marshal request body: %v", err)
		}
		reqBody = bytes.NewReader(b)
	} else {
		reqBody = bytes.NewReader(nil)
	}

	req, err := http.NewRequest(method, url, reqBody)
	if err != nil {
		t.Fatalf("new request: %v", err)
	}
	req.Header.Set("Content-Type", "application/json")

	resp, err := client.Do(req)
	if err != nil {
		t.Fatalf("do request: %v", err)
	}
	if resp.StatusCode != wantStatus {
		t.Fatalf("unexpected status: got %d, want %d", resp.StatusCode, wantStatus)
	}
	return resp
}

// ---------------------------------------------------------------------------
// TestAPIOrderFullFlowCancel
//
// 1️⃣  POST   /api/v1/categories          → создаём категорию
// 2️⃣  POST   /api/v1/products            → создаём товар (ссылаемся на категорию)
// 3️⃣  POST   /api/v1/orders              → оформляем заказ (один товар)
// 4️⃣  POST   /api/v1/orders/{id}/cancel  → отменяем заказ
// ---------------------------------------------------------------------------
func TestAPIOrderFullFlowCancel(t *testing.T) {
	// -----------------------------------------------------------------------
	// 1. Подготовка инфраструктуры (in‑memory SQLite + полностью
	//    сконфигурированный HTTP‑сервер)
	// -----------------------------------------------------------------------
	db := sqlite.SetupTestDB(t) // создаёт DB, применяет миграции и seed‑данные
	uc := usecase.NewAllUsecases(db) // ProductUsecase, CategoryUsecase, OrderUsecase, …
	h := handler.NewRouter(uc)        // chi‑router со всеми эндпоинтами

	srv := httptest.NewServer(h)
	defer srv.Close()
	client := srv.Client()

	// -----------------------------------------------------------------------
	// 2. Создаём категорию
	// -----------------------------------------------------------------------
	catPayload := map[string]any{
		"name":        "Espresso",
		"description": "Кофе‑напитки на основе эспрессо",
		"sort_order":  1,
	}
	resp := doRequest(t, client, http.MethodPost, srv.URL+"/api/v1/categories", catPayload, http.StatusCreated)
	var catResp struct {
		ID int64 `json:"id"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&catResp); err != nil {
		t.Fatalf("decode category response: %v", err)
	}
	if catResp.ID == 0 {
		t.Fatalf("unexpected category id: %d", catResp.ID)
	}
	resp.Body.Close()

	// -----------------------------------------------------------------------
	// 3. Добавляем товар, привязывая его к только‑что созданной категории
	// -----------------------------------------------------------------------
	prodPayload := map[string]any{
		"name":        "Cappuccino",
		"description": "Капучино с молочной пеной",
		"price":       640, // руб.
		"category_id": catResp.ID,
		"image_url":   "https://example.com/cappuccino.jpg",
		"active":      true,
	}
	resp = doRequest(t, client, http.MethodPost, srv.URL+"/api/v1/products", prodPayload, http.StatusCreated)
	var prodResp struct {
		ID int64 `json:"id"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&prodResp); err != nil {
		t.Fatalf("decode product response: %v", err)
	}
	if prodResp.ID == 0 {
		t.Fatalf("unexpected product id: %d", prodResp.ID)
	}
	resp.Body.Close()

	// -----------------------------------------------------------------------
	// 4. Оформляем заказ – в теле передаём массив items с product_id и qty
	// -----------------------------------------------------------------------
	orderPayload := map[string]any{
		"items": []map[string]any{
			{
				"product_id": prodResp.ID,
				"quantity":   1,
			},
		},
	}
	resp = doRequest(t, client, http.MethodPost, srv.URL+"/api/v1/orders", orderPayload, http.StatusCreated)
	var orderResp struct {
		ID    int64   `json:"id"`
		Total float64 `json:"total"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&orderResp); err != nil {
		t.Fatalf("decode order response: %v", err)
	}
	if orderResp.ID == 0 {
		t.Fatalf("unexpected order id: %d", orderResp.ID)
	}
	// проверяем, что total посчитан правильно (1 * 640 = 640)
	if orderResp.Total != 640 {
		t.Fatalf("unexpected order total: got %v, want %v", orderResp.Total, 640)
	}
	resp.Body.Close()

	// -----------------------------------------------------------------------
	// 5. Отменяем заказ
	// -----------------------------------------------------------------------
	cancelURL := srv.URL + "/api/v1/orders/" + strconv.FormatInt(orderResp.ID, 10) + "/cancel"
	resp = doRequest(t, client, http.MethodPost, cancelURL, nil, http.StatusOK)

	// Ответ отмены обычно пустой, но проверяем, что статус 200 и тело пусто
	if resp.ContentLength != 0 && resp.ContentLength != -1 {
		t.Fatalf("expected empty body on cancel, got %d bytes", resp.ContentLength)
	}
	resp.Body.Close()

	// -----------------------------------------------------------------------
	// 6. Финальная проверка – получаем заказ и убеждаемся, что статус = "cancelled"
	// -----------------------------------------------------------------------
	getURL := srv.URL + "/api/v1/orders/" + strconv.FormatInt(orderResp.ID, 10)
	resp = doRequest(t, client, http.MethodGet, getURL, nil, http.StatusOK)

	var orderGet struct {
		ID     int64  `json:"id"`
		Status string `json:"status"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&orderGet); err != nil {
		t.Fatalf("decode get‑order response: %v", err)
	}
	if orderGet.Status != "cancelled" {
		t.Fatalf("order status after cancel: got %q, want %q", orderGet.Status, "cancelled")
	}
	resp.Body.Close()
}
```

### Что делает тест

| Шаг | Действие | Ожидаемый результат |
|-----|----------|---------------------|
| 1️⃣ | **Создание категории** (`POST /api/v1/categories`) | Возвращается `201 Created` и `id > 0`. |
| 2️⃣ | **Создание товара** (`POST /api/v1/products`) | Товар привязан к только‑что созданной категории, получаем `id > 0`. |
| 3️⃣ | **Оформление заказа** (`POST /api/v1/orders`) | Считается `total = price * qty` (640 ₽), возвращается `id > 0`. |
| 4️⃣ | **Отмена заказа** (`POST /api/v1/orders/{id}/cancel`) | Возвращается `200 OK`, статус заказа меняется на `cancelled`. |
| 5️⃣ | **Проверка статуса** (`GET /api/v1/orders/{id}`) | В ответе поле `status` равно `"cancelled"`.|

### Где разместить

* Файл — `internal/handler/api_test.go` (можно добавить в конец существующего файла).  
* Тест использует уже существующие вспомогательные функции `sqlite.SetupTestDB` и `usecase.NewAllUsecases`, а также публичный конструктор роутера `handler.NewRouter`.  
* Он полностью изолирован: каждый запуск создаёт собственную in‑memory SQLite‑БД, поэтому не конфликтует с другими тестами.

### Как запустить

```bash
go test ./... -run TestAPIOrderFullFlowCancel -count=1
```

Тест будет выполнен вместе со всеми
